import Vision
import UIKit

struct VisionClassifier {
    struct Label {
        let identifier: String
        let confidence: Float
    }

    private let queue = DispatchQueue(label: "vision.classify",
                                      qos: .userInitiated)

    /// Returns up to `maxResults` labels with confidence ≥ `threshold`.
    func classify(image: UIImage,
                  threshold: Float = 0.5,
                  maxResults: Int = 5,
                  completion: @escaping (Result<[Label], Error>) -> Void) {
        guard let cgImage = image.cgImage else {
            completion(.failure(ClassifierError.noCGImage))
            return
        }

        queue.async {
            let request = VNClassifyImageRequest()
            // Use the image's natural orientation so Vision reads it right-side up.
            let handler = VNImageRequestHandler(cgImage: cgImage,
                                               orientation: image.cgImageOrientation,
                                               options: [:])
            do {
                try handler.perform([request])
                let observations = (request.results ?? [])
                    .filter { $0.confidence >= threshold }
                    .prefix(maxResults)
                    .map { Label(identifier: $0.identifier, confidence: $0.confidence) }
                completion(.success(Array(observations)))
            } catch {
                completion(.failure(error))
            }
        }
    }
}

enum ClassifierError: Error { case noCGImage }

// UIImage extension to read EXIF orientation as a CGImagePropertyOrientation.
extension UIImage {
    var cgImageOrientation: CGImagePropertyOrientation {
        switch imageOrientation {
        case .up:            return .up
        case .down:          return .down
        case .left:          return .left
        case .right:         return .right
        case .upMirrored:    return .upMirrored
        case .downMirrored:  return .downMirrored
        case .leftMirrored:  return .leftMirrored
        case .rightMirrored: return .rightMirrored
        @unknown default:    return .up
        }
    }
}

extension VisionClassifier {
    func classify(image: UIImage,
                  threshold: Float = 0.5,
                  maxResults: Int = 5) async throws -> [Label] {
        try await withCheckedThrowingContinuation { continuation in
            classify(image: image,
                     threshold: threshold,
                     maxResults: maxResults) { result in
                continuation.resume(with: result)
            }
        }
    }
}

func buildClaudePrompt(from labels: [VisionClassifier.Label],
                        userQuestion: String) -> String {
    let labelList = labels
        .map { "\($0.identifier) (\(Int($0.confidence * 100))%)" }
        .joined(separator: ", ")
    return """
    The device camera classified this image using on-device Vision. \
    Detected labels: \(labelList).

    User question: \(userQuestion)

    Answer based on what these labels suggest. If the labels do not \
    provide enough information, say so briefly.
    """
}

// Example usage inside a ViewModel
@MainActor
class ScanViewModel: ObservableObject {
    @Published var answer = ""
    @Published var isLoading = false

    private let classifier = VisionClassifier()
    private let claude = ClaudeClient()

    func analyze(image: UIImage, question: String) {
        isLoading = true
        Task {
            do {
                let labels = try await classifier.classify(
                    image: image, threshold: 0.45, maxResults: 6)
                let prompt = buildClaudePrompt(from: labels,
                                               userQuestion: question)
                let apiKey = try KeychainManager().retrieve(key: "claude-api-key")
                answer = try await claude.chat(
                    prompt: prompt, apiKey: apiKey)
            } catch {
                answer = "Error: \(error.localizedDescription)"
            }
            isLoading = false
        }
    }
}

final class CameraClassifierCoordinator: NSObject, AVCaptureVideoDataOutputSampleBufferDelegate {
    private let visionQueue = DispatchQueue(label: "vision.live",
                                            qos: .userInitiated)
    private var isProcessing = false

    var onLabels: (([VisionClassifier.Label]) -> Void)?

    func captureOutput(_ output: AVCaptureOutput,
                       didOutput sampleBuffer: CMSampleBuffer,
                       from connection: AVCaptureConnection) {
        guard !isProcessing else { return }  // drop frame if busy
        isProcessing = true

        visionQueue.async { [weak self] in
            defer { self?.isProcessing = false }

            guard let pixelBuffer = CMSampleBufferGetImageBuffer(sampleBuffer) else { return }
            let request = VNClassifyImageRequest()
            let handler = VNImageRequestHandler(cvPixelBuffer: pixelBuffer,
                                               orientation: .up,
                                               options: [:])
            do {
                try handler.perform([request])
                let labels = (request.results ?? [])
                    .filter { $0.confidence >= 0.5 }
                    .prefix(4)
                    .map { VisionClassifier.Label(identifier: $0.identifier,
                                                  confidence: $0.confidence) }
                DispatchQueue.main.async {
                    self?.onLabels?(Array(labels))
                }
            } catch {
                // Silent drop — camera frames are ephemeral
            }
        }
    }
}

protocol ImageClassifier {
    func classify(image: UIImage,
                  threshold: Float,
                  maxResults: Int) async throws -> [VisionClassifier.Label]
}

extension VisionClassifier: ImageClassifier {}

// Test stub
struct StubClassifier: ImageClassifier {
    let labels: [VisionClassifier.Label]

    func classify(image: UIImage,
                  threshold: Float,
                  maxResults: Int) async throws -> [VisionClassifier.Label] {
        labels.filter { $0.confidence >= threshold }.prefix(maxResults).map { $0 }
    }
}

// XCTest
final class ScanViewModelTests: XCTestCase {
    func testHighConfidenceLabelReachesPrompt() async throws {
        let stub = StubClassifier(labels: [
            .init(identifier: "cat", confidence: 0.92),
            .init(identifier: "animal", confidence: 0.98)
        ])
        let prompt = buildClaudePrompt(
            from: try await stub.classify(image: UIImage(),
                                          threshold: 0.5,
                                          maxResults: 5),
            userQuestion: "What animal is this?")
        XCTAssertTrue(prompt.contains("cat"))
        XCTAssertTrue(prompt.contains("animal"))
    }
}
